// Slot 0 interlock
val slot0Interlock = (0 until p.instructionLanes).map(i =>
  if (i == 0) {
    true.B
  } else {
    !decodedInsts(0).forceSlot0Only() && !decodedInsts(i).forceSlot0Only()
  }
)

